def translate_phrase(source_phrase, target_language, equivalence_type='dynamic'):
    translations = {
        'It is raining cats and dogs': {
            'dynamic': 'It is raining heavily.',
            'formal': 'It is raining cats and dogs.'
        },
        'C est la fin du monde': {
            'dynamic': 'It s the end of the world.',
            'formal': 'C est la fin du monde.'
        }
    }

    return translations.get(source_phrase, {}).get(equivalence_type, 'Translation not available')

# Example usage
print(translate_phrase('It is raining cats and dogs', 'French', 'dynamic'))  # Output: 'It is raining heavily.'
print(translate_phrase('C est la fin du monde', 'English', 'formal'))  # Output: 'C est la fin du monde.'
